                    <div style={{ padding: '6px 14px 4px', fontSize: 10, fontWeight: 700, color: txt3, textTransform: 'uppercase', letterSpacing: '0.07em', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>Solution</div>
